import{c as o,Q as t,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Boris Cherny on verification loops","description":"","frontmatter":{"url":"https://x.com/bcherny/status/2007179861115511237","title":"Boris Cherny on verification loops","domain":"x.com","fetched":"2026-05-12T00:00:00.000Z","source_tier":"C"},"headers":[],"relativePath":"research/ai-articles/2026-05-12-boris-cherny-verification-loops.md","filePath":"research/ai-articles/2026-05-12-boris-cherny-verification-loops.md","lastUpdated":1779894392000}'),a={name:"research/ai-articles/2026-05-12-boris-cherny-verification-loops.md"};function s(n,e,l,c,h,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="boris-cherny-on-verification-loops" tabindex="-1">Boris Cherny on Verification Loops <a class="header-anchor" href="#boris-cherny-on-verification-loops" aria-label="Permalink to &quot;Boris Cherny on Verification Loops&quot;">​</a></h1><p><strong>Original Tweet Thread by Boris Cherny (@bcherny)</strong><strong>Date</strong>: Tweet part of larger thread on Claude Code best practices <strong>Author</strong>: Boris Cherny, creator of Claude Code at Anthropic</p><hr><h2 id="core-message-verification-loops-2-3x-quality-improvement" tabindex="-1">Core Message: Verification Loops = 2-3x Quality Improvement <a class="header-anchor" href="#core-message-verification-loops-2-3x-quality-improvement" aria-label="Permalink to &quot;Core Message: Verification Loops = 2-3x Quality Improvement&quot;">​</a></h2><blockquote><p>&quot;A final tip: probably the most important thing to get great results out of Claude Code -- give Claude a way to verify its work. If Claude has that feedback loop, it will 2-3x the quality of the final result. Claude tests every single change I land.&quot;</p></blockquote><h3 id="key-insight" tabindex="-1">Key Insight <a class="header-anchor" href="#key-insight" aria-label="Permalink to &quot;Key Insight&quot;">​</a></h3><p>Verification loops are <strong>the single most impactful optimization</strong> for Claude Code output quality.</p><p><strong>Impact</strong>: Proper verification increases output quality by <strong>2-3x</strong></p><h3 id="what-verification-looks-like" tabindex="-1">What Verification Looks Like <a class="header-anchor" href="#what-verification-looks-like" aria-label="Permalink to &quot;What Verification Looks Like&quot;">​</a></h3><p>Verification is domain-specific and can take multiple forms:</p><ul><li><strong>Running tests</strong>: Automated test suites validate code changes</li><li><strong>Bash commands</strong>: Simple shell commands that verify output correctness</li><li><strong>UI testing</strong>: Testing the application in a browser or phone simulator</li><li><strong>Screenshots comparison</strong>: Visually comparing before/after outputs</li><li><strong>Custom validation</strong>: Any mechanism that provides feedback on whether the result is correct</li></ul><h3 id="practical-application" tabindex="-1">Practical Application <a class="header-anchor" href="#practical-application" aria-label="Permalink to &quot;Practical Application&quot;">​</a></h3><p>According to Boris Cherny&#39;s workflow:</p><ul><li>Every single change he lands goes through verification</li><li>For very long-running tasks, he uses background agents or Stop hooks to verify completion</li><li>The ralph-wiggum plugin is used for additional verification in some workflows</li></ul><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Without clear success criteria and verification, Claude might produce something that <strong>looks right but actually doesn&#39;t work</strong>. When Claude has a feedback loop, it becomes self-correcting rather than requiring manual human review for every output.</p><p>This transforms Claude from &quot;needs review after every change&quot; to &quot;self-verifying and trustworthy output.&quot;</p><h3 id="related-best-practices-from-boris-cherny" tabindex="-1">Related Best Practices from Boris Cherny <a class="header-anchor" href="#related-best-practices-from-boris-cherny" aria-label="Permalink to &quot;Related Best Practices from Boris Cherny&quot;">​</a></h3><ul><li>Use <code>/loop</code> and <code>/schedule</code> for automated verification on intervals</li><li>Configure Stop hooks to verify work deterministically</li><li>Integrate background agents for verification of long-running tasks</li><li>Combine verification with proper prompting and context management</li></ul><hr><h2 id="context-boris-cherny-s-role" tabindex="-1">Context: Boris Cherny&#39;s Role <a class="header-anchor" href="#context-boris-cherny-s-role" aria-label="Permalink to &quot;Context: Boris Cherny&#39;s Role&quot;">​</a></h2><p>Boris Cherny is the creator of Claude Code at Anthropic. As of 2026, he:</p><ul><li>Hasn&#39;t hand-written a single line of code (fully agentic)</li><li>Merges 50-150 PRs daily from his phone using hundreds of agents and loops</li><li>Shares internal Anthropic workflows publicly to help developers use Claude Code effectively</li></ul><p>This guidance comes from his direct experience building and shipping code entirely through Claude Code with autonomous agents.</p>',24)])])}const f=o(a,[["render",s]]);export{d as __pageData,f as default};
